class Solution:
    def canPartitionGrid(self, grid):
        m = len(grid)
        n = len(grid[0])
        total = sum(sum(row) for row in grid)

        def connected(cells, removed):
            rem = set(cells)
            rem.discard(removed)
            if not rem:
                return False
            start = next(iter(rem))
            stack = [start]
            seen = {start}
            while stack:
                x, y = stack.pop()
                for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    nb = (x + dx, y + dy)
                    if nb in rem and nb not in seen:
                        seen.add(nb)
                        stack.append(nb)
            return len(seen) == len(rem)

        def ok(cellsA, cellsB):
            sa = sum(grid[i][j] for i, j in cellsA)
            sb = sum(grid[i][j] for i, j in cellsB)
            if sa == sb:
                return True
            big, small, sbig = (cellsA, sb, sa) if sa > sb else (cellsB, sa, sb)
            diff = sbig - small
            for (i, j) in big:
                if grid[i][j] == diff and connected(big, (i, j)):
                    return True
            return False

        for r in range(1, m):
            top = [(i, j) for i in range(r) for j in range(n)]
            bot = [(i, j) for i in range(r, m) for j in range(n)]
            if ok(top, bot):
                return True
        for c in range(1, n):
            left = [(i, j) for i in range(m) for j in range(c)]
            right = [(i, j) for i in range(m) for j in range(c, n)]
            if ok(left, right):
                return True
        return False

