class Solution:
    def canPartitionGrid(self, grid):
        m = len(grid)
        n = len(grid[0])
        rowSum = [sum(row) for row in grid]
        colSum = [0] * n
        for i in range(m):
            for j in range(n):
                colSum[j] += grid[i][j]
        total = sum(rowSum)

        def heavy_has(diff, cells_iter, both_dims, ends):
            # both_dims True -> any cell with value diff works
            # else only the end cells (given explicitly) may be removed
            if both_dims:
                for v in cells_iter:
                    if v == diff:
                        return True
                return False
            for v in ends:
                if v == diff:
                    return True
            return False

        # horizontal cuts: top = rows[0..r), section is (rows) x n
        topPref = 0
        topValues = set()
        for r in range(1, m):
            topPref += rowSum[r - 1]
            for j in range(n):
                topValues.add(grid[r - 1][j])
            sa = topPref
            sb = total - topPref
            if sa == sb:
                return True
            if sa > sb:
                diff = sa - sb
                rows = r
                section_rows = range(0, r)
            else:
                diff = sb - sa
                rows = m - r
                section_rows = range(r, m)
            both = (rows >= 2 and n >= 2)
            if both:
                # need diff present anywhere in those rows
                found = False
                for i in section_rows:
                    if diff in grid[i]:
                        found = True
                        break
                if found:
                    return True
            else:
                # single row block (rows==1) -> ends are col 0 and col n-1
                # single column overall (n==1) -> ends are first and last row of block
                ends = []
                rs = list(section_rows)
                if n == 1:
                    ends = [grid[rs[0]][0], grid[rs[-1]][0]]
                else:
                    ends = [grid[rs[0]][0], grid[rs[0]][n - 1]]
                if diff in ends:
                    return True

        # vertical cuts: left = cols[0..c), section is m x (cols)
        leftPref = 0
        for c in range(1, n):
            leftPref += colSum[c - 1]
            sa = leftPref
            sb = total - leftPref
            if sa == sb:
                return True
            if sa > sb:
                diff = sa - sb
                cols = c
                section_cols = range(0, c)
            else:
                diff = sb - sa
                cols = n - c
                section_cols = range(c, n)
            both = (cols >= 2 and m >= 2)
            if both:
                found = False
                for i in range(m):
                    row = grid[i]
                    for j in section_cols:
                        if row[j] == diff:
                            found = True
                            break
                    if found:
                        break
                if found:
                    return True
            else:
                cs = list(section_cols)
                if m == 1:
                    ends = [grid[0][cs[0]], grid[0][cs[-1]]]
                else:
                    ends = [grid[0][cs[0]], grid[m - 1][cs[0]]]
                if diff in ends:
                    return True
        return False

