var canPartitionGrid = function(grid) {
    const m = grid.length, n = grid[0].length;
    const rowSum = grid.map(r => r.reduce((a, b) => a + b, 0));
    const colSum = new Array(n).fill(0);
    for (let i = 0; i < m; i++) for (let j = 0; j < n; j++) colSum[j] += grid[i][j];
    let total = rowSum.reduce((a, b) => a + b, 0);

    let topPref = 0;
    for (let r = 1; r < m; r++) {
        topPref += rowSum[r - 1];
        const sa = topPref, sb = total - topPref;
        if (sa === sb) return true;
        let diff, lo, hi, rows;
        if (sa > sb) { diff = sa - sb; lo = 0; hi = r; }
        else { diff = sb - sa; lo = r; hi = m; }
        rows = hi - lo;
        const both = (rows >= 2 && n >= 2);
        if (both) {
            let found = false;
            for (let i = lo; i < hi && !found; i++) for (let j = 0; j < n; j++) if (grid[i][j] === diff) { found = true; break; }
            if (found) return true;
        } else {
            let ends;
            if (n === 1) ends = [grid[lo][0], grid[hi - 1][0]];
            else ends = [grid[lo][0], grid[lo][n - 1]];
            if (ends.indexOf(diff) !== -1) return true;
        }
    }

    let leftPref = 0;
    for (let c = 1; c < n; c++) {
        leftPref += colSum[c - 1];
        const sa = leftPref, sb = total - leftPref;
        if (sa === sb) return true;
        let diff, lo, hi, cols;
        if (sa > sb) { diff = sa - sb; lo = 0; hi = c; }
        else { diff = sb - sa; lo = c; hi = n; }
        cols = hi - lo;
        const both = (cols >= 2 && m >= 2);
        if (both) {
            let found = false;
            for (let i = 0; i < m && !found; i++) for (let j = lo; j < hi; j++) if (grid[i][j] === diff) { found = true; break; }
            if (found) return true;
        } else {
            let ends;
            if (m === 1) ends = [grid[0][lo], grid[0][hi - 1]];
            else ends = [grid[0][lo], grid[m - 1][lo]];
            if (ends.indexOf(diff) !== -1) return true;
        }
    }
    return false;
};
